#include <torch/extension.h>
#include <ATen/ATen.h>
#include <ATen/Functions.h>
#include "pytorch_npu_helper.hpp"

// Wrapper: run conv2d using PyTorch, then fused subtract-subtract-mish using custom kernel
at::Tensor conv2d_subtract_subtract_mish_impl_npu(const at::Tensor& x,
                                                  const at::Tensor& weight,
                                                  c10::optional<at::Tensor> bias,
                                                  double subtract_value_1,
                                                  double subtract_value_2) {
    // Use PyTorch's conv2d (stride=1, padding=0, dilation=1, groups=1)
    at::IntArrayRef stride({1, 1});
    at::IntArrayRef padding({0, 0});
    at::IntArrayRef dilation({1, 1});
    int64_t groups = 1;
    at::Tensor conv_out = at::conv2d(x, weight, bias, stride, padding, dilation, groups);

    // Apply fused subtract-subtract-mish with custom AscendC kernel
    at::Tensor result = at::empty_like(conv_out);
    EXEC_NPU_CMD(aclnnConv2dSubtractSubtractMishCustom, conv_out, subtract_value_1, subtract_value_2, result);
    return result;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("conv2d_subtract_subtract_mish_custom", &conv2d_subtract_subtract_mish_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
